*** Settings ***
Resource    ../resources/common_keywords.resource
Resource    ../pom_pages/login_page/login_page.resource
Test Teardown    Close Browser Session

*** Test Cases ***
AUT-AUTH-LOGIN01: Verify login page loads successfully
    [Tags]    LOGIN_TC_001    positive
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded

AUT-AUTH-LOGIN02: Login with valid username and valid password
    [Tags]    LOGIN_TC_002    positive
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button

AUT-AUTH-LOGIN03: Verify login failure with incorrect username and valid password
    [Tags]    LOGIN_TC_003    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${INVALID_USERNAME}
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN04: Verify login failure with valid username and incorrect password
    [Tags]    LOGIN_TC_004    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${INVALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN05: Verify login failure with both username and password incorrect
    [Tags]    LOGIN_TC_005    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${INVALID_USERNAME}
    Enter Password    ${INVALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN06: Verify login failure when username and password fields are blank
    [Tags]    LOGIN_TC_006    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${EMPTY}
    Enter Password    ${EMPTY}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN07: Verify login failure when username is blank and password is entered
    [Tags]    LOGIN_TC_007    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${EMPTY}
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button
    Verify Username Required Validation

AUT-AUTH-LOGIN08: Verify login failure when password is blank and username is entered
    [Tags]    LOGIN_TC_008    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${EMPTY}
    Click Sign In Button
    Verify Password Required Validation

AUT-AUTH-LOGIN09: Verify username field accepts leading and trailing spaces
    [Tags]    LOGIN_TC_009    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${SPACE}${VALID_USERNAME}${SPACE}
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN10: Verify password field with leading and trailing spaces
    [Tags]    LOGIN_TC_010    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${SPACE}${VALID_PASSWORD}${SPACE}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN11: Verify login behavior with very long username input
    [Tags]    LOGIN_TC_011    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}${VALID_USERNAME}${VALID_USERNAME}${VALID_USERNAME}${VALID_USERNAME}${VALID_USERNAME}
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN12: Verify login behavior with very long password input
    [Tags]    LOGIN_TC_012    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${VALID_PASSWORD}${VALID_PASSWORD}${VALID_PASSWORD}${VALID_PASSWORD}${VALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN13: Verify username field with special characters
    [Tags]    LOGIN_TC_013    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    !@#$%^&*()
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN14: Verify password field accepts special characters
    [Tags]    LOGIN_TC_014    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${VALID_PASSWORD}!@#
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN15: Verify case sensitivity of username
    [Tags]    LOGIN_TC_015    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    HAKLARR
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN16: Verify case sensitivity of password
    [Tags]    LOGIN_TC_016    negative
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    icstunnel1
    Click Sign In Button
    Verify Login Rejected

AUT-AUTH-LOGIN17: Verify login submission using keyboard Enter key
    [Tags]    LOGIN_TC_017    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${VALID_PASSWORD}
    Submit Login With Enter Key

AUT-AUTH-LOGIN18: Verify behavior when Login button is clicked multiple times quickly
    [Tags]    LOGIN_TC_018    edge
    Open Login Page    ${LOGIN_PAGE_URL}
    Verify Login Page Loaded
    Enter Username    ${VALID_USERNAME}
    Enter Password    ${VALID_PASSWORD}
    Click Sign In Button
    Click Sign In Button

